def median(nums):
    if not nums:
        return None
    sorted_nums = sorted(nums)
    mid_index = len(sorted_nums) // 2
    if len(sorted_nums) % 2 == 1:
        return sorted_nums[mid_index]
    else:
        return (sorted_nums[mid_index - 1] + sorted_nums[mid_index]) / 2
